diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9f034aba874a..6139d2496658 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -3345,6 +3345,82 @@ Instruction *InstCombinerImpl::foldICmpBinOpEqualityWithConstant(
         return new ICmpInst(Pred, BOp0, Neg);
       }
     }
+    // (add (ext i1 X), (ext i1 Y)) == C --> boolean expression
+    // (add (ext i1 X), (ext i1 Y)) != C --> inverted boolean expression
+    // where ext is zext or sext.
+    {
+      Value *X, *Y;
+      bool ZExt0, ZExt1;
+      if (match(BOp0, m_ZExtOrSExt(m_Value(X))) &&
+          match(BOp1, m_ZExtOrSExt(m_Value(Y))) &&
+          X->getType()->isIntOrIntVectorTy(1) &&
+          Y->getType()->isIntOrIntVectorTy(1)) {
+        ZExt0 = isa<ZExtInst>(BOp0);
+        ZExt1 = isa<ZExtInst>(BOp1);
+        // For zext: values are {0, 1}. For sext: values are {0, -1}.
+        // Possible sums:
+        // zext+zext: {0, 1, 2}
+        // sext+sext: {0, -1, -2}
+        // zext+sext: {-1, 0, 1}
+        bool Impossible = false;
+        Value *Result = nullptr;
+        if (ZExt0 && ZExt1) {
+          // zext + zext
+          if (C.isZero())
+            Result = Builder.CreateOr(X, Y); // eq 0: both false -> nor
+          else if (C.isOne())
+            Result = Builder.CreateXor(X, Y); // eq 1: exactly one
+          else if (C.getZExtValue() == 2)
+            Result = Builder.CreateAnd(X, Y); // eq 2: both true
+          else
+            Impossible = true;
+        } else if (!ZExt0 && !ZExt1) {
+          // sext + sext
+          if (C.isZero())
+            Result = Builder.CreateOr(X, Y); // eq 0: both false -> nor
+          else if (C.isAllOnes()) // -1
+            Result = Builder.CreateXor(X, Y); // eq -1: exactly one
+          else if (C.getSExtValue() == -2)
+            Result = Builder.CreateAnd(X, Y); // eq -2: both true
+          else
+            Impossible = true;
+        } else {
+          // zext + sext (or sext + zext)
+          Value *SextVal = ZExt0 ? Y : X;
+          Value *ZextVal = ZExt0 ? X : Y;
+          if (C.isAllOnes()) // -1
+            // sext=-1 (true), zext=0 (false) -> sext ∧ ¬zext
+            Result = Builder.CreateAnd(SextVal,
+                                       Builder.CreateNot(ZextVal));
+          else if (C.isZero())
+            // eq 0: both false or both true -> ¬(sext xor zext)
+            Result = Builder.CreateXor(SextVal, ZextVal);
+          else if (C.isOne())
+            // sext=0, zext=1 -> ¬sext ∧ zext
+            Result = Builder.CreateAnd(ZextVal,
+                                       Builder.CreateNot(SextVal));
+          else
+            Impossible = true;
+        }
+        if (Impossible) {
+          // No possible inputs produce this sum.
+          return replaceInstUsesWith(
+              Cmp, ConstantInt::getBool(Cmp.getType(), isICMP_NE));
+        }
+        // For eq 0 cases, we computed the OR or XOR of the conditions that
+        // make the sum zero, but we need the negation.
+        // zext+zext C==0: OR means both false, we need NOR = ¬(X ∨ Y).
+        // sext+sext C==0: OR means both false, we need NOR = ¬(X ∨ Y).
+        // mixed C==0: XOR means values differ, sum=0 when values equal,
+        //             so we need ¬(X xor Y) = X == Y.
+        if (C.isZero())
+          Result = Builder.CreateNot(Result);
+        // For the ne predicate, invert the result.
+        if (isICMP_NE)
+          Result = Builder.CreateNot(Result);
+        return replaceInstUsesWith(Cmp, Result);
+      }
+    }
     break;
   }
   case Instruction::Xor:

